public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
{
    super(_entityCtx, _dataSourceCtx);

    ETGACFParameters    ETGACFParameters;
    CompanyInfo         companyInfo;

    //SB, DLT, 27/04/2026, Introducing a new parameter to identity entity for global entities
    select companyInfo 
        where companyInfo.ETGDmsIntegrationGlobal == NoYes::Yes;
    select crosscompany ETGACFParameters 
        where ETGACFParameters.DataAreaId == companyInfo.DataArea;

    if(ETGACFParameters.EnableDMSIntegration == NoYes::Yes)
    {
        if (_dataSourceCtx.name() == dataEntityDataSourceStr(ETGIntercompanyTradingRelationEntity, InterCompanyTradingRelation))
        {
            InterCompanyTradingRelation relBuffer = _dataSourceCtx.getBuffer();

            if (relBuffer.RecId == 0)
            {
                InterCompanyTradingPartner vendorPartner;
                InterCompanyTradingPartner customerPartner;

                vendorPartner = InterCompanyTradingPartner::findOrCreateVendor(
                            this.VendorParty,
                            this.VendorDataAreaId);

                customerPartner = InterCompanyTradingPartner::findOrCreateCustomer(
                            this.CustomerParty,
                            this.CustomerDataAreaId);

                if (!vendorPartner.RecId || !customerPartner.RecId)
                {
                    throw error("Vendor or Customer trading partner could not be created.");
                }

                relBuffer.InterCompanyTradingVendor   = vendorPartner.RecId;
                relBuffer.InterCompanyTradingCustomer = customerPartner.RecId;

                relBuffer.Active = this.Active;;
            }
        }
    }
}
